(function () {
  'use strict';

  /* ── DATA ── */
  var SELAWAT = [
    {
      name: 'Selawat Ibrahimiyyah',
      cat: 'Paling Afdhal',
      arabic: 'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ وَعَلَى آلِ سَيِّدِنَا مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى سَيِّدِنَا إِبْرَاهِيمَ وَعَلَى آلِ سَيِّدِنَا إِبْرَاهِيمَ وَبَارِكْ عَلَى سَيِّدِنَا مُحَمَّدٍ وَعَلَى آلِ سَيِّدِنَا مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى سَيِّدِنَا إِبْرَاهِيمَ وَعَلَى آلِ سَيِّدِنَا إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ',
      rumi: 'Allahumma solli \'ala Sayyidina Muhammadin wa \'ala ali Sayyidina Muhammadin, kama sollaita \'ala Sayyidina Ibrahima wa \'ala ali Sayyidina Ibrahima, wa barik \'ala Sayyidina Muhammadin wa \'ala ali Sayyidina Muhammadin, kama barakta \'ala Sayyidina Ibrahima wa \'ala ali Sayyidina Ibrahima, fil \'alamin innaka Hamidum Majid.',
      mksud: '"Ya Allah, limpahkanlah rahmat kepada penghulu kami Nabi Muhammad dan keluarganya sebagaimana Engkau merahmati dan memberkati Nabi Ibrahim dan keluarganya di sekalian alam. Sesungguhnya Engkau Maha Terpuji lagi Maha Mulia."',
      info: 'Diajarkan terus oleh Rasulullah ﷺ kepada para sahabat - selawat paling sahih dan utama.',
      ref: '📚 Sahih al-Bukhari (No. 2497) · Sahih Muslim (No. 405)'
    },
    {
      name: 'Selawat Tafrijiyyah',
      cat: 'Lapangkan Hajat',
      arabic: 'اللَّهُمَّ صَلِّ صَلَاةً كَامِلَةً وَسَلِّمْ سَلَامًا تَامًّا عَلَى سَيِّدِنَا مُحَمَّدٍ الَّذِي تَنْحَلُّ بِهِ الْعُقَدُ وَتَنْفَرِجُ بِهِ الْكُرَبُ وَتُقْضَى بِهِ الْحَوَائِجُ وَتُنَالُ بِهِ الرَّغَائِبُ وَحُسْنُ الْخَوَاتِيمِ وَيُسْتَسْقَى الْغَمَامُ بِوَجْهِهِ الْكَرِيمِ وَعَلَى آلِهِ وَصَحْبِهِ فِي كُلِّ لَمْحَةٍ وَنَفَسٍ بِعَدَدِ كُلِّ مَعْلُومٍ لَكَ',
      rumi: 'Allahumma solli solatan kamilatan wa sallim salaman tamman \'ala Sayyidina Muhammadin allazi tanhallu bihil \'uqadu wa tanfariju bihil kurabu wa tuqda bihil hawa\'iju wa tunalu bihir ragha\'ibu wa husnul khawatim wa yustasqal ghamamu biwajhihil karim wa \'ala alihi wa sohbihi fi kulli lamhatin wa nafasin bi\'adadi kulli ma\'lumin lak.',
      mksud: '"Ya Allah, limpahkanlah rahmat yang sempurna dan salam yang menyeluruh kepada Nabi Muhammad yang dengannya terurai segala masalah, terhapus kesusahan, tertunai hajat, dan dicurahkan hujan rahmat dengan berkat wajahnya yang mulia."',
      info: 'Disahkan halal diamalkan - tiada unsur syirik oleh Mufti WP & Mufti Selangor.',
      ref: '📚 Disusun oleh Sheikh Abu Ishaq Ibrahim Al-Taazi Al-Wahrani | Tashih Al-Mafahim #20'
    },
    {
      name: 'Selawat Jibril',
      cat: 'Amalan Harian',
      arabic: 'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِهِ وَسَلِّمْ',
      rumi: 'Allahumma solli \'ala Muhammadin wa alihi wa sallim.',
      mksud: '"Ya Allah, selawatlah ke atas Nabi Muhammad dan ahli keluarganya serta berilah kesejahteraan kepada mereka."',
      info: 'Ringkas dan mudah dihafal - sesuai diamalkan pada bila-bila masa sepanjang hari.',
      ref: '📚 Dipercayai diajarkan oleh Malaikat Jibril AS kepada Rasulullah ﷺ'
    },
    {
      name: 'Selawat Marhaban',
      cat: 'Majlis & Sambutan',
      arabic: 'صَلَّى اللهُ عَلَى مُحَمَّدْ ✦ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ\nيَا نَبِيْ سَلاَمٌ عَلَيْكَ ✦ يَا رَسُوْلُ سَلاَمٌ عَلَيْكَ\nيَا حَبِيْبُ سَلاَمٌ عَلَيْكَ ✦ صَلَوَاتُ اللهِ عَلَيْكَ',
      rumi: 'Sollallahu \'ala Muhammad, sollallahu \'alayhi wasallam.\nYa Nabi salaamun \'alayk, ya Rasul salaamun \'alayk,\nYa Habib salaamun \'alayk, solawatullahi \'alayk.',
      mksud: '"Selawat Allah ke atas Muhammad, selawat dan salam Allah ke atas baginda. Wahai Nabi, salam atasmu. Wahai Rasul, salam atasmu. Wahai kekasih Allah, salam atasmu. Selawat Allah ke atasmu."',
      info: 'Popular dalam majlis Maulidur Rasul di masjid dan surau seluruh Malaysia.',
      ref: '📚 Selawat tradisi Melayu - dibaca dalam sambutan Maulidur Rasul peringkat negara'
    },
    {
      name: 'Selawat Munjiyyat',
      cat: 'Doa Penyelamat',
      arabic: 'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ صَلَاةً تُنْجِيْنَا بِهَا مِنْ جَمِيْعِ الأَهْوَالِ وَالآفَاتِ وَتَقْضِيْ لَنَا بِهَا جَمِيْعَ الحَاجَاتِ وَتُطَهِّرُنَا بِهَا مِنْ جَمِيْعِ السَّيِّئَاتِ وَتَرْفَعُنَا بِهَا عِنْدَكَ أَعْلَى الدَّرَجَاتِ وَتُبَلِّغُنَا بِهَا أَقْصَى الغَايَاتِ مِنْ جَمِيْعِ الخَيْرَاتِ فِي الحَيَاةِ وَبَعْدَ المَمَاتِ',
      rumi: 'Allahumma solli \'ala Sayyidina Muhammadin solatan tunjina biha min jami\'il ahwali wal afat, wa taqdi lana biha jami\'al hajat, wa tutahhiruna biha min jami\'is sayyi\'at, wa tarfa\'una biha \'indaka a\'lad darajat, wa tuballighuna biha aqsal ghayat min jami\'il khayrati fil hayati wa ba\'dal mamat.',
      mksud: '"Ya Allah, limpahkanlah selawat ke atas Nabi Muhammad, sebagai selawat yang menyelamatkan kami dari semua bala, menyelesaikan semua keperluan, menyucikan dari keburukan, mengangkat darjat kami, dan menyampaikan ke puncak segala kebaikan semasa hidup dan selepas mati."',
      info: 'Selawat penawar duka dan pembuka jalan - diamalkan dalam majlis zikir para ulama.',
      ref: '📚 Amalan para ulama dan ahli zikir - merangkumi permohonan menyeluruh dunia dan akhirat'
    },
    {
      name: 'Selawat Ringkas',
      cat: 'Mudah & Cepat',
      arabic: 'اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ',
      rumi: 'Allahumma solli \'ala Muhammadin wa \'ala ali Muhammad.',
      mksud: '"Ya Allah, selawatkanlah ke atas Nabi Muhammad dan ke atas keluarga Nabi Muhammad."',
      info: 'Selawat paling mudah untuk diamalkan pada bila-bila masa - semasa memandu, memasak, atau bekerja.',
      ref: '📚 Hadis Riwayat An-Nasa\'i (No. 1292) - Sahih'
    }
  ];

  var state = {
    current: 0,
    count: 0,
    target: 33,
    bookmarks: JSON.parse((function(){try{return localStorage.getItem('ilmxslwt_bm')||'[]';}catch(e){return'[]';}}())),
    rumiOn: false,
    mksudOn: false
  };

  /* ── ELEMENTS ── */
  var $ = function(id){ return document.getElementById(id); };
  var eArabic    = $('ilmxslwt-arabic');
  var eName      = $('ilmxslwt-name');
  var eCat       = $('ilmxslwt-cat');
  var eRumi      = $('ilmxslwt-rumi');
  var eMksud     = $('ilmxslwt-mksud');
  var eInfo      = $('ilmxslwt-info');
  var eRef       = $('ilmxslwt-ref');
  var eRumiBtn   = $('ilmxslwt-rumi-btn');
  var eMksudBtn  = $('ilmxslwt-mksud-btn');
  var eCount     = $('ilmxslwt-count');
  var eOf        = $('ilmxslwt-of');
  var eRing      = $('ilmxslwt-ring');
  var eTapBtn    = $('ilmxslwt-tap-btn');
  var eComplete  = $('ilmxslwt-complete');
  var eBmSection = $('ilmxslwt-bm-section');
  var eBmList    = $('ilmxslwt-bm-list');
  var eBmToggle  = $('ilmxslwt-bm-toggle');
  var eUndo      = $('ilmxslwt-undo');
  var eReset     = $('ilmxslwt-reset');
  var eWa        = $('ilmxslwt-wa');
  var eCopy      = $('ilmxslwt-copy');
  var eBm        = $('ilmxslwt-bookmark');

  var CIRCUMFERENCE = 408.41;

  function updateRing() {
    var pct = Math.min(state.count / state.target, 1);
    var offset = CIRCUMFERENCE * (1 - pct);
    eRing.style.strokeDashoffset = offset;
    eCount.textContent = state.count;
    eOf.textContent = '/ ' + state.target;
    if (state.count >= state.target) {
      eTapBtn.classList.add('done');
      eTapBtn.textContent = '✅ Alhamdulillah - Sasaran Tercapai!';
      if (!eComplete.classList.contains('show')) {
        eComplete.classList.add('show');
      }
    } else {
      eTapBtn.classList.remove('done');
      eTapBtn.innerHTML = 'ﷺ &nbsp; Klik untuk Berselawat';
      eComplete.classList.remove('show');
    }
  }

  function loadSelawat(idx) {
    var s = SELAWAT[idx];
    eName.textContent = s.name;
    eCat.textContent  = s.cat;
    eArabic.innerHTML = s.arabic.replace(/\n/g, '<br>');
    eRumi.innerHTML   = s.rumi.replace(/\n/g, '<br>');
    eMksud.textContent = s.mksud;
    eInfo.textContent  = s.info;
    eRef.textContent   = s.ref;
    state.current = idx;
    // reset toggles
    state.rumiOn  = false;
    state.mksudOn = false;
    eRumi.classList.remove('show');
    eMksud.classList.remove('show');
    eRumiBtn.classList.remove('on');
    eMksudBtn.classList.remove('on');
    // reset counter
    state.count = 0;
    updateRing();
  }

  /* ── TAB CLICKS ── */
  var tabs = document.querySelectorAll('.ilmxslwttool-tab');
  tabs.forEach(function(tab) {
    tab.addEventListener('click', function() {
      tabs.forEach(function(t){ t.classList.remove('active'); t.setAttribute('aria-selected','false'); });
      tab.classList.add('active');
      tab.setAttribute('aria-selected','true');
      loadSelawat(parseInt(tab.getAttribute('data-slwt'), 10));
    });
  });

  /* ── TOGGLE RUMI / MKSUD ── */
  eRumiBtn.addEventListener('click', function() {
    state.rumiOn = !state.rumiOn;
    eRumi.classList.toggle('show', state.rumiOn);
    eRumiBtn.classList.toggle('on', state.rumiOn);
  });
  eMksudBtn.addEventListener('click', function() {
    state.mksudOn = !state.mksudOn;
    eMksud.classList.toggle('show', state.mksudOn);
    eMksudBtn.classList.toggle('on', state.mksudOn);
  });

  /* ── TARGET SELECTION ── */
  var targetBtns = document.querySelectorAll('.ilmxslwttool-counter-target');
  targetBtns.forEach(function(btn) {
    btn.addEventListener('click', function() {
      targetBtns.forEach(function(b){ b.classList.remove('selected'); });
      btn.classList.add('selected');
      state.target = parseInt(btn.getAttribute('data-target'), 10);
      state.count = 0;
      updateRing();
    });
  });

  /* ── TAP TO COUNT ── */
  eTapBtn.addEventListener('click', function() {
    if (state.count < state.target) {
      state.count++;
      updateRing();
    }
  });

  /* ── UNDO ── */
  eUndo.addEventListener('click', function() {
    if (state.count > 0) {
      state.count--;
      updateRing();
    }
  });

  /* ── RESET ── */
  eReset.addEventListener('click', function() {
    state.count = 0;
    updateRing();
  });

  /* ── BOOKMARK TOGGLE ── */
  eBmToggle.addEventListener('click', function() {
    eBmSection.classList.toggle('show');
  });

  /* ── BOOKMARK SAVE ── */
  eBm.addEventListener('click', function() {
    var name = SELAWAT[state.current].name;
    if (state.bookmarks.indexOf(name) === -1) {
      state.bookmarks.push(name);
      try { localStorage.setItem('ilmxslwt_bm', JSON.stringify(state.bookmarks)); } catch(e) {}
      renderBookmarks();
    }
    eBmSection.classList.add('show');
  });

  function renderBookmarks() {
    if (state.bookmarks.length === 0) {
      eBmList.innerHTML = '<span style="font-size:0.8rem;color:#999;font-family:-apple-system,sans-serif;">Tiada bookmark lagi.</span>';
      return;
    }
    eBmList.innerHTML = '';
    state.bookmarks.forEach(function(name, i) {
      var btn = document.createElement('button');
      btn.className = 'ilmxslwttool-bm-item';
      btn.textContent = name;
      btn.setAttribute('data-idx', i);
      btn.addEventListener('click', function() {
        var idx = SELAWAT.findIndex(function(s){ return s.name === name; });
        if (idx !== -1) {
          tabs.forEach(function(t){ t.classList.remove('active'); });
          if (tabs[idx]) tabs[idx].classList.add('active');
          loadSelawat(idx);
        }
      });
      eBmList.appendChild(btn);
    });
  }
  renderBookmarks();

  /* ── SHARE: WHATSAPP ── */
  eWa.addEventListener('click', function() {
    var s = SELAWAT[state.current];
    var txt = s.name + '\n\n' + s.arabic + '\n\n' + s.rumi + '\n\n' + s.mksud + '\n\nDaripada: ' + window.location.href;
    window.open('https://api.whatsapp.com/send?text=' + encodeURIComponent(txt), '_blank');
  });

  /* ── SHARE: COPY ── */
  eCopy.addEventListener('click', function() {
    var s = SELAWAT[state.current];
    var txt = s.name + '\n\n' + s.arabic + '\n\n' + s.rumi + '\n\n' + s.mksud;
    if (navigator.clipboard) {
      navigator.clipboard.writeText(txt).then(function() {
        var orig = eCopy.textContent;
        eCopy.textContent = '✅ Disalin!';
        setTimeout(function(){ eCopy.textContent = orig; }, 2000);
      });
    }
  });

  /* ── FAQ ACCORDION ── */
  setTimeout(function() {
    var faqQs = document.querySelectorAll('.ilmx-slwt-faq-q');
    faqQs.forEach(function(btn) {
      btn.addEventListener('click', function() {
        var answer = btn.nextElementSibling;
        var isOpen = btn.classList.contains('open');
        // close all
        faqQs.forEach(function(b) {
          b.classList.remove('open');
          b.setAttribute('aria-expanded', 'false');
          if (b.nextElementSibling) b.nextElementSibling.classList.remove('open');
        });
        if (!isOpen) {
          btn.classList.add('open');
          btn.setAttribute('aria-expanded', 'true');
          answer.classList.add('open');
        }
      });
    });
  }, 300);

  /* ── INIT ── */
  updateRing();

})();
